func withScriptWithParams[ParamArgsType AllParamConstraint](
	queryRequest *QueryRequest[ParamArgsType],
	source *string,
	scriptId *string,
	filter *FilterAssociation[ParamArgsType],
) *QueryRequest[ParamArgsType] {
	if len(filter.paramArgs) == 0 {
		return queryRequest
	}

	if source == nil && scriptId == nil {
		return queryRequest
	}

	if queryRequest.Script == nil {
		queryRequest.Script = &Script[ParamArgsType]{}
	}

	if scriptId != nil {
		queryRequest.Script.Id = scriptId
	} else {
		queryRequest.Script.Source = source
		queryRequest.Script.Lang = scriptLanguage
	}

	var scriptParamArgs *[]ParamArgsType
	if queryRequest.Script.Params == nil {
		args := make([]ParamArgsType, 0, len(filter.paramArgs))
		scriptParamArgs = &args
		queryRequest.Script.Params = &Param[ParamArgsType]{
			Args: scriptParamArgs,
		}
	} else {
		scriptParamArgs = queryRequest.Script.Params.Args
		scriptParamArgsLength := len(*scriptParamArgs)
		newScriptParamArgs := make([]ParamArgsType, scriptParamArgsLength, scriptParamArgsLength+len(filter.paramArgs))
		copy(newScriptParamArgs, *scriptParamArgs)
		*scriptParamArgs = newScriptParamArgs
	}

	for _, paramArgs := range filter.ParamArgs() {
		*scriptParamArgs = append(*scriptParamArgs, paramArgs)
	}

	return queryRequest
}

