)

type IndexMissingPropertiesDetector interface {
	Start(context context.Context, logContext *log.Context)
	Stop()
	Done() <-chan struct{}
	DetectAndRemediate(
		logContext *log.Context,
		tenantUuid *string,
	)
}

type indexMissingPropertiesDetector struct {
	driftDetector              *driftDetector
	schemaMapper               schemaMapping.SchemaMapper
	scheduler                  scheduler.Scheduler
	done                       chan struct{}
	client                     repository.NoSqlRepository
	schedulerInterval          time.Duration
	schedulerIntervalFormatted string
	searchBatchSize            int
	remediationRequestInterval time.Duration
}

func NewIndexMissingPropertiesDetector(
	schemaMapper schemaMapping.SchemaMapper,
	scheduler scheduler.Scheduler,
	client repository.NoSqlRepository,
	remediationRequestEmitter emitter.RemediationRequestEmitter,
	schedulerInterval time.Duration,
	searchBatchSize int,
	remediationRequestInterval time.Duration,
) IndexMissingPropertiesDetector {
	return &indexMissingPropertiesDetector{
		driftDetector: newDriftDetector(
			client,
			remediationRequestEmitter,
			remediationRequestInterval,
		),
		schemaMapper:               schemaMapper,
		scheduler:                  scheduler,
		done:                       make(chan struct{}),
		client:                     client,
		schedulerInterval:          schedulerInterval,
		schedulerIntervalFormatted: repository.FormatDuration(schedulerInterval),
		searchBatchSize:            searchBatchSize,
		remediationRequestInterval: remediationRequestInterval,
	}
}

func (s *indexMissingPropertiesDetector) Start(context context.Context, logContext *log.Context) {
	const startingMissingIndexRequiredPropertiesDetectorMessage = "index_missing_properties_detector.Start: starting scheduler for index missing properties detector."

	log.Infow(logContext, startingMissingIndexRequiredPropertiesDetectorMessage)

	// perform an initial remediation of indices with missing properties before
	// monitoring at regular interval.
	go s.remediateIndexWithMissingProperties(logContext, nil)

	s.scheduler.Start(
		context,
		func() { s.remediateIndexWithMissingProperties(logContext, nil) },
		s.schedulerInterval,
	)
}

func (s *indexMissingPropertiesDetector) Stop() {
	s.scheduler.Stop()
	close(s.done)
}

func (s *indexMissingPropertiesDetector) Done() <-chan struct{} {
	return s.done
}

func (s *indexMissingPropertiesDetector) DetectAndRemediate(
	logContext *log.Context,
	tenantUuid *string,
) {
	const startingMissingIndexRequiredPropertiesDetectorMessage = "index_missing_properties_detector.DetectAndRemediate: Detecting and remediating indices with missing required properties."

	log.Infow(logContext, startingMissingIndexRequiredPropertiesDetectorMessage, log.TenantUuidKey, tenantUuid)

	s.remediateIndexWithMissingProperties(logContext, tenantUuid)
}

// remediateIndexWithMissingProperties identifies and remediates indices that
// are missing required properties.
//
// Parameters:
//   - logContext: *log.Context - Used for logging operations and maintaining
//     context.
//   - tenantUuid: *string - UUID of the tenant for which to perform
//     remediation.  If nil, search is performed across all tenants.
func (s *indexMissingPropertiesDetector) remediateIndexWithMissingProperties(
	logContext *log.Context,
	tenantUuid *string,
) {
	const (
		functionName                                    = "index_missing_properties_detector.remediateIndexWithMissingProperties"
		skipIndexRemediationFeatureDisabled             = "index_missing_properties_detector.remediateIndexWithMissingProperties: skipping remediation attempt on %s because the feature flag %s is disabled"
		startIndexMissingPropertiesDetectionMessage     = "index_missing_properties_detector.remediateIndexWithMissingProperties: starting index missing properties detection and remediation."
		searchingForDocumentsWithMissingProperties      = "index_missing_properties_detector.remediateIndexWithMissingProperties: searching for documents in %s index with missing properties"
		completedIndexMissingPropertiesDetectionMessage = "index_missing_properties_detector.remediateIndexWithMissingProperties: completed index missing properties detection and remediation. Waiting for next schedule in %s."
		errorOccurredWhileRemediatingIndex              = "index_missing_properties_detector.remediateIndexWithMissingProperties: Error occurred when remediating documents in %s index"
	)

	var (
		indexMetadata *schemaMapping.IndexMetadata
		err           error
	)

	defer errorHandling.Recover(logContext, nil)

	log.Infow(logContext, startIndexMissingPropertiesDetectionMessage, log.TenantUuidKey, tenantUuid)

	for indexKey, remediationConfig := range s.schemaMapper.GetIndexRemediationConfigMap() {
		if remediationConfig == nil || len(remediationConfig.RequiredProperties) == 0 {
			continue
		}

		indexMetadata, _ = s.schemaMapper.GetIndexMetadataByIndexKey(indexKey)

		if len(remediationConfig.RequiredProperties) == 0 {
			continue
		}

		if remediationConfig.FeatureFlag != nil && !ff.IsEnabled(*remediationConfig.FeatureFlag, false) {
			log.Warnw(
				logContext,
				fmt.Sprintf(
					skipIndexRemediationFeatureDisabled,
					indexKey,
					*remediationConfig.FeatureFlag,
				),
			)

			continue
		}

		query := s.createIndexMissingPropertiesSearchQuery(
			logContext,
			tenantUuid,
			indexKey,
			remediationConfig.RequiredProperties,
			indexMetadata.DefaultValuesMap,
		)

		log.Infow(
			logContext,
			fmt.Sprintf(searchingForDocumentsWithMissingProperties, indexKey),
			log.TenantUuidKey,
			tenantUuid,
		)

		err = s.driftDetector.detectAndRemediateDrift(
			logContext,
			functionName,
			remediationConfig.EntitySchemaName,
			remediationConfig,
			tenantUuid,
			query,
		)

		if err != nil {
			// log and move to the next index
			log.Errorw(
				logContext,
				fmt.Sprintf(errorOccurredWhileRemediatingIndex, indexKey),
				log.ErrorKey,
				err,
				log.TenantUuidKey,
				tenantUuid,
				log.IndexName,
				indexKey,
				log.ErrorResponse,
				errorHandling.GetData[*repository.AnyResponse](err),
			)
		}
	}

	log.Infof(logContext, completedIndexMissingPropertiesDetectionMessage, s.schedulerIntervalFormatted)
}

// createIndexMissingPropertiesSearchQuery creates a query to search for index
// documents where the given properties are either missing or have the default
// value.
func (s *indexMissingPropertiesDetector) createIndexMissingPropertiesSearchQuery(
	logContext *log.Context,
	tenantUuid *string,
	indexKey string,
	properties []string,
	defaultValues map[string]any,
) *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]] {
	queryBody := repository.NewMissingOrDefaultPropertiesQueryRequest[repository.Params](
		logContext,
		tenantUuid,
		properties,
		defaultValues,
	)

	queryBody.
		WithSize(s.searchBatchSize).
		WithSort(map[string]string{"_id": "asc"}).
		WithSource(properties)

	query := &repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
		Indices:    []string{indexKey},
		Body:       queryBody,
		LogContext: queryBody.LogContext,
	}

	return query
}
